class Solution {
    inOrderTraversal(root) {
        const result = [];
        this._inOrderTraversalHelper(root, result);
        console.log(result.join(' '));
    }

    _inOrderTraversalHelper(root, result) {
        if (root === null) return;
        this._inOrderTraversalHelper(root.left, result);
        result.push(root.val);
        this._inOrderTraversalHelper(root.right, result);
    }
}
